// @ts-nocheck
import { create } from 'zustand';

/** Jump from Server Logs (etc.) → Query Store with a SQL fingerprint. */
export const useQueryStoreNavStore = create((set, get) => ({
  loadToken: 0,
  payload: null,

  openQuery: (payload) => {
    set({
      loadToken: get().loadToken + 1,
      payload: {
        connectionId: payload.connectionId,
        sqlText: String(payload.sqlText ?? '').trim(),
        queryId: payload.queryId ? String(payload.queryId) : null,
      },
    });
  },
}));
